  const token = req.headers.authorization?.replace(/^Bearer\s+/i, '');
  if (!token || !verifyToken(token)) return res.sendStatus(401);
  next();
}

app.get('/users', requireAuth, (req, res) => {
  res.json(users.map(({ id, name }) => ({ id, name }))); // drop email by default
});
```

### 4. No rate limiting (Low)
A single client can hammer `/health` or `/users` without limit.

**Recommendation:**
```js
const rateLimit = require('express-rate-limit');
app.use(rateLimit({ windowMs: 60_000, max: 120 })); // 120 req/min/IP
```

### 5. No global error handler (Low)
Express's default error handler leaks stack traces when `NODE_ENV !== 'production'`. Add an explicit handler that logs server-side and returns a generic message.

**Recommendation:**
```js
// After all routes
app.use((err, req, res, next) => {
  console.error(err);               // send to real logger in prod
  res.status(err.status || 500).json({ error: 'Internal Server Error' });
});
```

### 6. TLS / transport security (Info)
