## Suggested hardened `app.js`

```js
const express = require('express');
const helmet = require('helmet');
const cors = require('cors');
const morgan = require('morgan');
const rateLimit = require('express-rate-limit');

const app = express();
app.disable('x-powered-by');
app.set('trust proxy', 1);

app.use(helmet());
app.use(cors({ origin: (process.env.CORS_ORIGINS || '').split(',').filter(Boolean) }));
app.use(express.json({ limit: '100kb' }));
app.use(morgan('combined'));

const apiLimiter = rateLimit({ windowMs: 60_000, max: 60 });
app.use(apiLimiter);

function requireAuth(req, res, next) {
  // Replace with real auth (JWT verify, session check, etc.)
  if (!req.headers.authorization) return res.status(401).json({ error: 'unauthorized' });
  next();
}

app.get('/health', (_req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

app.get('/users', requireAuth, (_req, res) => {
  const users = [
    { id: 1, name: 'Alice' },
    { id: 2, name: 'Bob' },
  ];
  res.json(users);
});

app.use((err, _req, res, _next) => {
  console.error(err);
  res.status(500).json({ error: 'internal_error' });
});

const PORT = Number(process.env.PORT) || 3000;
const HOST = process.env.HOST || '127.0.0.1';
const server = app.listen(PORT, HOST, () => {
  console.log(`listening on ${HOST}:${PORT}`);
});

process.on('SIGTERM', () => server.close(() => process.exit(0)));
process.on('unhandledRejection', (r) => console.error('unhandledRejection', r));

module.exports = app;
```

